import os
import tarfile

def extract_tar(user_path, destination):
    if not os.path.exists(user_path):
        print("File does not exist")
        return False
    
    if not user_path.endswith('.tar'):
        print("Not a tar file.")
        return False
        
    try: 
        tar = tarfile.open(user_path)
        tar.extractall(path=destination)
        tar.close()
    except Exception as e:
        print('Error extracting the tar file', str(e))
        return False
    
    print("Tar file extracted successfully")
    return True